#!/usr/bin/env bash
# Generated by bun-bench Harbor export adapter. Oracle reference solution.
# Overwrites the starter source under /app with the bun-bench reference.
set -euo pipefail

mkdir -p /app/src
cat > /app/src/server.ts <<'BUN_BENCH_SOLUTION_EOF'
const port = Number(Bun.env.PORT ?? 3000);

type Scope = "files:read" | "files:write" | "files:delete";

const TOKENS: Record<string, Scope[]> = {
  "tok-ro": ["files:read"],
  "tok-rw": ["files:read", "files:write"],
  "tok-admin": ["files:read", "files:write", "files:delete"],
};

type FileRecord = { id: string; name: string };

const files = new Map<string, FileRecord>();
let seq = 0;

function authenticate(request: Request): Scope[] | null {
  const header = request.headers.get("authorization");
  if (!header) return null;
  const match = /^Bearer\s+(.+)$/.exec(header.trim());
  if (!match) return null;
  const token = match[1].trim();
  return TOKENS[token] ?? null;
}

const unauthorized = () => Response.json({ error: "unauthorized" }, { status: 401 });

function insufficientScope(required: Scope): Response {
  return Response.json(
    { error: "insufficient_scope" },
    { status: 403, headers: { "WWW-Authenticate": `Bearer scope="${required}"` } },
  );
}

Bun.serve({
  port,
  async fetch(request) {
    const url = new URL(request.url);
    const segments = url.pathname.split("/").filter(Boolean);

    const scopes = authenticate(request);
    if (!scopes) return unauthorized();

    // GET /files  (requires files:read)
    if (request.method === "GET" && url.pathname === "/files") {
      if (!scopes.includes("files:read")) return insufficientScope("files:read");
      return Response.json({ files: [...files.values()] }, { status: 200 });
    }

    // POST /files  (requires files:write)
    if (request.method === "POST" && url.pathname === "/files") {
      if (!scopes.includes("files:write")) return insufficientScope("files:write");
      let body: unknown;
      try {
        body = await request.json();
      } catch {
        return Response.json({ error: "invalid_json" }, { status: 400 });
      }
      const record = body as Record<string, unknown> | null;
      if (!record || typeof record.name !== "string") {
        return Response.json({ error: "invalid_body" }, { status: 422 });
      }
      seq += 1;
      const file: FileRecord = { id: String(seq), name: record.name };
      files.set(file.id, file);
      return Response.json(file, { status: 201 });
    }

    // DELETE /files/:id  (requires files:delete)
    if (request.method === "DELETE" && segments.length === 2 && segments[0] === "files") {
      if (!scopes.includes("files:delete")) return insufficientScope("files:delete");
      const id = segments[1];
      if (!files.has(id)) return Response.json({ error: "not_found" }, { status: 404 });
      files.delete(id);
      return new Response(null, { status: 204 });
    }

    return Response.json({ error: "not_found" }, { status: 404 });
  },
});

console.log(`scoped-tokens reference listening on ${port}`);
BUN_BENCH_SOLUTION_EOF
